init_eqs:
// clear buffer
i = 0; loop(1024*1024, gmegabuf(i) = 0; i = i+1;);

count = 50;
attributes = 32;
nListStart = 24; // starting index of neighbor list

minradius = 0.01;
maxradius = 0.0333;
v = 0.0;

// randomize initial coordinates
index = 0;
loop(count,
gmegabuf(index*attributes) = rand(1000)/1000;
gmegabuf(index*attributes+1) = rand(1000)/1000;
gmegabuf(index*attributes+2) = v*(rand(1000)/1000-0.5);
gmegabuf(index*attributes+3) = v*(rand(1000)/1000-0.5);
gmegabuf(index*attributes+4) = minradius + (maxradius-minradius)*(index+1)/count;
gmegabuf(index*attributes+5) = rand(1000)/1000;
gmegabuf(index*attributes+6) = rand(1000)/1000;
gmegabuf(index*attributes+7) = rand(1000)/1000;
gmegabuf(index*attributes+8) = pow(gmegabuf(index*attributes+4),3) ;
gmegabuf(index*attributes+9) = 4*asin(1)*rand(1000)/1000;
gmegabuf(index*attributes+10) = 0;
gmegabuf(index*attributes+13) = index/count;
index = index+1;
);

q30 = nListStart;
q31 = count;
q32 = attributes;

// 0, x
// 1, y
