frame_eqs:
random = rand(1000)/1000;

dt = 1/fps;
bend_force = bend_force*0.92 - 4*bend*dt + 2*(random-0.5)*dt;

bend = bend + 60*bend_force*dt;
q3 = bend*4;

monitor = bend;

warp = 0;
zoom = 1;

gravity = 0.0015*dt*0;
dampening = 0.;
friction = 2048*dt;
shock = 0.002;
pi2 = asin(1);

nn = 3; // number of nearest neighbors to search, reduce if not needed
// provide enough attributes, otherwise the next object's coordinate will be overwritten
// collision detection is based on nearest neighbors, so keep it at least at 1.

check = 2; // how many neighbors will be checked for a possible collision. may not be above nn.
// raise to avoid odd behavior in clusters of touching objects.

bouncefactor = 0.1;
rotatefactor = 0.0; // relation between angular and translative momentum, when object hits a border. this is an empirical value for a convincing impression



h = (aspecty-1)*0.5; w = (aspectx-1)*0.5;
index = 0; index2 = 0;
loop(count,

random = rand(1000)/1000;
sample = gmegabuf(index+13);

// bend force
gmegabuf(index + 11) = gmegabuf(index + 11)*0.92 - 4*gmegabuf(index+12)*dt + 2*(random-0.5)*dt*(bass*0.4*sample + treb*0.5*(1-sample));

// bend
gmegabuf(index + 12) += 60*gmegabuf(index + 11)*dt;

v = sqrt( sqr( gmegabuf(index + 2) ) + sqr( gmegabuf(index + 3) ) );

// apply friction
fric = max(0,1 - sqr(v*friction) - v*2);
gmegabuf(index + 2) *= fric;
gmegabuf(index + 3) *= fric;

// apply direction change
gmegabuf(index + 10) = gmegabuf(index + 10)*fric +  v*gmegabuf(index +12)*0;

// apply acceleration force
acceleration = random*0.000 + abs(gmegabuf(index+11))*0.003;
direction = gmegabuf(index + 9) - pi2;
gmegabuf(index + 2) += sin(direction)*acceleration;
gmegabuf(index + 3) += cos(direction)*acceleration;

// adding velocity vectors
gmegabuf(index) = gmegabuf(index) + gmegabuf(index+2)*60*dt;
gmegabuf(index+1) = gmegabuf(index+1) + gmegabuf(index+3)*60*dt;
gmegabuf(index+9) = gmegabuf(index+9) + gmegabuf(index+10)*0.5;

// applying gravity
gmegabuf(index+3) = gmegabuf(index+3) - gravity;

vr = sin(gmegabuf(index+10))*gmegabuf(index+4); // rotation speed at the surface

// bounce off ceiling
bounce = above( gmegabuf(index+1), 1 - gmegabuf(index+4) + w);
gmegabuf(index+2) = if( bounce, gmegabuf(index+2) + (vr+gmegabuf(index+2))*rotatefactor, gmegabuf(index+2));
gmegabuf(index+3) = if( bounce, -abs(gmegabuf(index+3))*dampening - shock, gmegabuf(index+3));
vr = if( bounce, vr - (gmegabuf(index+2) + vr)*(1-rotatefactor), vr);

// bounce off floor
bounce = below( gmegabuf(index+1), gmegabuf(index+4) - w);
gmegabuf(index+2) = if( bounce, gmegabuf(index+2) + (vr-gmegabuf(index+2))*rotatefactor, gmegabuf(index+2));
gmegabuf(index+3) = if( bounce, abs(gmegabuf(index+3))*dampening + shock, gmegabuf(index+3));
vr = if( bounce, vr + (gmegabuf(index+2) - vr)*(1-rotatefactor), vr);

// bounce off right border
bounce = above( gmegabuf(index), 1 - gmegabuf(index+4) + h);
gmegabuf(index+2) = if( bounce, -abs(gmegabuf(index+2))*dampening - shock, gmegabuf(index+2));
gmegabuf(index+3) = if( bounce, gmegabuf(index+3) + (vr-gmegabuf(index+3))*rotatefactor, gmegabuf(index+3));
vr = if( bounce, vr + (gmegabuf(index+3) - vr)*(1-rotatefactor), vr);

// bounce off left border
bounce = below( gmegabuf(index), gmegabuf(index+4) - h);
gmegabuf(index+2) = if( bounce, abs(gmegabuf(index+2))*dampening + shock, gmegabuf(index+2));
gmegabuf(index+3) = if( bounce, gmegabuf(index+3) - (vr+gmegabuf(index+3))*rotatefactor, gmegabuf(index+3));
vr = if( bounce, vr - (gmegabuf(index+3) + vr)*(1-rotatefactor), vr);

gmegabuf(index+10) = asin(vr/gmegabuf(index+4));

i = 0; j = 0; // collecting pairs of index and distance to the current object in a local buffer
loop( count,
d = sqrt( sqr(gmegabuf(index)-gmegabuf(i)) + sqr(gmegabuf(index+1)-gmegabuf(i+1)));
d = if( equal(d,0), 10, d); // leave out comparison with itself (where d == 0, set d to a high value)
d = d - (gmegabuf(index+4)+gmegabuf(i+4))*0.5; // subtract radius (surface to surface distance)
megabuf(j)   = i; // store index/distance pairs
megabuf(j+1) = d;
j = j+2;
i = i+attributes; );
i = 0; // sort that buffer, but only as many cycles as needed for the _nn_ nearest neighbors
loop( nn,
j = i; smallestfind = 10; findindex = -1;
loop( count-j,
distance =megabuf(j*2+1);
smaller = above( smallestfind, distance);
smallestfind = if(smaller, distance, smallestfind);
findindex = if( smaller, j*2, findindex);
j = j + 1; );
j = megabuf(i*2); d = megabuf(i*2+1);
megabuf(i*2)   = megabuf(findindex);
megabuf(i*2+1) = megabuf(findindex+1);
megabuf(findindex)   = j;
megabuf(findindex+1) = d;
i = i+1;
);
i = 0; // storing the indexes of the nearest neighbors in the list
loop( nn,
gmegabuf(index + nListStart + i) = megabuf(i*2);
i = i +1;
);
i = 0; // collision detection and impulse transmission below
loop( check,
index2 = megabuf(i);
hit = below( sqrt( sqr( gmegabuf(index) - gmegabuf(index2)) +
sqr( gmegabuf(index+1) - gmegabuf(index2+1))),
gmegabuf(index + 4) + gmegabuf(index2 + 4)
)
*
above( sqrt( sqr( gmegabuf(index)   - gmegabuf(index2))+
sqr( gmegabuf(index+1) - gmegabuf(index2+1))),
sqrt( sqr( gmegabuf(index+0) - gmegabuf(index2+0)+
gmegabuf(index+2) - gmegabuf(index2+2))+
sqr( gmegabuf(index+1) - gmegabuf(index2+1)+
gmegabuf(index+3) - gmegabuf(index2+3)) ) );
ref_ang = atan2( gmegabuf(index2)-gmegabuf(index), // calculating the angle of the common tangent
gmegabuf(index2 + 1)-gmegabuf(index + 1)) + pi2;
v1 = sqrt(sqr( gmegabuf(index + 2)) + sqr( gmegabuf(index + 3))); // velocity of object1
v2 = sqrt(sqr( gmegabuf(index2 + 2)) + sqr( gmegabuf(index2 + 3)));  // velocity of object2
w1 = atan2( gmegabuf(index + 2), gmegabuf(index + 3));   // object1 motion angle
w2 = atan2( gmegabuf(index2 + 2), gmegabuf(index2 + 3)); // object2 motion angle
vr2 = sin(gmegabuf(index2 + 10))*gmegabuf(index2+4); // the other object's surface velocity
m1 = gmegabuf(index + 8); m2 = gmegabuf(index2 + 8);
vv1 = ((m1-m2)*v1 + 2*m2*v2)/(m1+m2); vv2 = ((m2-m1)*v2 + 2*m1*v1)/(m1+m2);
vrr = ((m1-m2)*vr + 2*m2*vr2)/(m1+m2); vrr2 = ((m2-m1)*vr2 + 2*m1*vr)/(m1+m2);

gmegabuf( index + 2) = if( hit, sin(ref_ang)*v1*cos(w1-ref_ang) + ((vr-vr2)-sin(ref_ang)*v1*cos(w1-ref_ang))*rotatefactor
+ cos(ref_ang)*vv1*sin(w2-ref_ang),
gmegabuf( index + 2) );

gmegabuf( index + 3) = if( hit, cos(ref_ang)*v1*cos(w1-ref_ang) + ((vr-vr2)-cos(ref_ang)*v1*cos(w1-ref_ang))*rotatefactor
- sin(ref_ang)*vv1*sin(w2-ref_ang),
gmegabuf( index + 3) );

gmegabuf( index2 + 2) = if( hit, sin(ref_ang)*v2*cos(w2-ref_ang) + ((vr2-vr)-sin(ref_ang)*v2*cos(w2-ref_ang))*rotatefactor
+ cos(ref_ang)*vv2*sin(w1-ref_ang),
gmegabuf( index2 + 2) );

gmegabuf( index2 + 3) = if( hit, cos(ref_ang)*v2*cos(w2-ref_ang) + ((vr2-vr)-cos(ref_ang)*v2*cos(w2-ref_ang))*rotatefactor
- sin(ref_ang)*vv2*sin(w1-ref_ang),
gmegabuf( index2 + 3) );

vr = if( hit, vrr + (cos(w1-ref_ang)*(v1-v2)-vrr)*(1-rotatefactor) , vr);
gmegabuf( index + 10) = asin( vr / gmegabuf(index+4) );

vr2 = if( hit, vrr2 + (cos(w2-ref_ang)*(v2-v1)-vrr2)*(1-rotatefactor) , vr2);
gmegabuf( index2 + 10) = asin( vr2 / gmegabuf(index2+4) );

i=i+2;
);
index = index+attributes;
);


